package com.jdmedia.service;
import com.jdmedia.model.ConversionRecord;import java.nio.file.*;import java.sql.*;import java.time.Instant;import java.util.*;
public final class HistoryService {private final String url;public HistoryService(){Path db=Path.of(System.getProperty("user.home"),".jd-media-converter","history.db");try{Files.createDirectories(db.getParent());}catch(Exception ignored){}url="jdbc:sqlite:"+db;initialize();}private void initialize(){try(Connection c=DriverManager.getConnection(url);Statement s=c.createStatement()){s.executeUpdate("CREATE TABLE IF NOT EXISTS conversions (started_at TEXT, source TEXT, output TEXT, original_bytes INTEGER, final_bytes INTEGER, elapsed_seconds INTEGER, configuration TEXT, result TEXT)");try{s.executeUpdate("ALTER TABLE conversions ADD COLUMN output TEXT");}catch(SQLException ignored){}}catch(SQLException ignored){}}public void add(ConversionRecord r){try(Connection c=DriverManager.getConnection(url);PreparedStatement s=c.prepareStatement("INSERT INTO conversions(started_at,source,output,original_bytes,final_bytes,elapsed_seconds,configuration,result) VALUES(?,?,?,?,?,?,?,?)")){s.setString(1,r.startedAt().toString());s.setString(2,r.source());s.setString(3,r.output());s.setLong(4,r.originalBytes());s.setLong(5,r.finalBytes());s.setLong(6,r.elapsedSeconds());s.setString(7,r.configuration());s.setString(8,r.result());s.executeUpdate();}catch(SQLException ignored){}}public List<ConversionRecord> recent(){List<ConversionRecord> result=new ArrayList<>();try(Connection c=DriverManager.getConnection(url);Statement s=c.createStatement();ResultSet rs=s.executeQuery("SELECT started_at,source,output,original_bytes,final_bytes,elapsed_seconds,configuration,result FROM conversions ORDER BY started_at DESC LIMIT 100")){while(rs.next())result.add(new ConversionRecord(Instant.parse(rs.getString(1)),rs.getString(2),rs.getString(3),rs.getLong(4),rs.getLong(5),rs.getLong(6),rs.getString(7),rs.getString(8)));}catch(SQLException ignored){}return result;}}
